import base64
import gzip

# Compressed application source. It expands in memory so the project can run
# without storing any local configuration or credentials in the repository.
_SOURCE_GZIP_BASE64 = """

"""

_source = gzip.decompress(base64.b64decode(_SOURCE_GZIP_BASE64)).decode("utf-8")
_namespace = {"__name__": __name__, "__file__": __file__}
exec(compile(_source, __file__, "exec"), _namespace)
